    #{createTime}, #{lastUpdateTime}, #{createBy}, #{lastUpdateBy}
)

mapper.select:
SELECT a.*, c.name_cn AS category_name FROM openplatform_v2_api_t a LEFT JOIN openplatform_v2_category_t c ON a.category_id = c.id
AND a.category_id = #{categoryId}
AND a.status = #{status}
AND (a.name_cn LIKE CONCAT('%', #{keyword}, '%') OR a.name_en LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM openplatform_v2_permission_t p WHERE p.resource_type = 'api' AND p.resource_id = a.id AND p.scope LIKE CONCAT('%', #{keyword}, '%') ))
ORDER BY a.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM openplatform_v2_api_t a
AND a.category_id = #{categoryId}
AND a.status = #{status}
AND (a.name_cn LIKE CONCAT('%', #{keyword}, '%') OR a.name_en LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM openplatform_v2_permission_t p WHERE p.resource_type = 'api' AND p.resource_id = a.id AND p.scope LIKE CONCAT('%', #{keyword}, '%') ))

SELECT COUNT(*)
FROM openplatform_v2_api_t
WHERE category_id = #{categoryId}
